import anthropic, json

client = anthropic.Anthropic()

tools = [
    {
        "name": "search_documents",
        "description": (
            "Search the knowledge base for documents matching a query. "
            "Use this when the user asks a factual question about products, policies, or procedures."
        ),
        "input_schema": {
            "type": "object",
            "properties": {"query": {"type": "string", "description": "Search query"}},
            "required": ["query"]
        }
    },
    {
        "name": "create_ticket",
        "description": (
            "Create a support ticket in the issue tracker. "
            "Use this when the user reports a bug, requests a feature, or needs follow-up that cannot be resolved immediately."
        ),
        "input_schema": {
            "type": "object",
            "properties": {
                "title":    {"type": "string"},
                "body":     {"type": "string"},
                "priority": {"type": "string", "enum": ["low", "medium", "high"]}
            },
            "required": ["title", "body", "priority"]
        }
    },
    {
        "name": "send_email",
        "description": (
            "Send an email to a customer. "
            "Use only after getting explicit confirmation from the user that they want an email sent."
        ),
        "input_schema": {
            "type": "object",
            "properties": {
                "to":      {"type": "string"},
                "subject": {"type": "string"},
                "body":    {"type": "string"}
            },
            "required": ["to", "subject", "body"]
        }
    }
]

test_messages = [
    "What is your refund policy?",        # → search_documents
    "I found a bug in the checkout flow", # → create_ticket
    "Send me a summary email",            # → asks for confirmation first (no email without explicit OK)
    "How do I reset my password?",        # → search_documents
]

for msg in test_messages:
    response = client.messages.create(
        model="claude-sonnet-4-6", max_tokens=256, tools=tools,
        messages=[{"role": "user", "content": msg}]
    )
    calls = [b.name for b in response.content if b.type == "tool_use"]
    print(f"  {msg!r}")
    print(f"  → {calls or ['(text answer)']}")
    print()

# With many tools (>10), group them by domain in the description
# and use a two-stage approach: first select the category, then call within it.

# Stage 1: category-selection tools (meta-tools)
CATEGORY_TOOLS = [
    {
        "name": "use_crm_tools",
        "description": "Use CRM tools for customer records, orders, subscriptions.",
        "input_schema": {"type": "object", "properties": {"intent": {"type": "string"}}, "required": ["intent"]}
    },
    {
        "name": "use_docs_tools",
        "description": "Use documentation tools for product info, policies, FAQs.",
        "input_schema": {"type": "object", "properties": {"intent": {"type": "string"}}, "required": ["intent"]}
    },
    {
        "name": "use_comms_tools",
        "description": "Use communication tools for email, SMS, notifications.",
        "input_schema": {"type": "object", "properties": {"intent": {"type": "string"}}, "required": ["intent"]}
    },
]

# Stage 2: actual domain tools (presented only when category is selected)
CRM_TOOLS     = [get_customer_tool, get_order_tool, update_subscription_tool]
DOCS_TOOLS    = [search_kb_tool, get_faq_tool]
COMMS_TOOLS   = [send_email_tool, send_sms_tool]

CATEGORY_MAP = {
    "use_crm_tools":   CRM_TOOLS,
    "use_docs_tools":  DOCS_TOOLS,
    "use_comms_tools": COMMS_TOOLS,
}

def two_stage_agent(user_msg: str) -> str:
    # Turn 1: select category
    r1 = client.messages.create(
        model="claude-sonnet-4-6", max_tokens=256,
        tools=CATEGORY_TOOLS,
        messages=[{"role": "user", "content": user_msg}]
    )
    if r1.stop_reason != "tool_use":
        return next(b.text for b in r1.content if hasattr(b, "text"))

    cat_block = next(b for b in r1.content if b.type == "tool_use")
    domain_tools = CATEGORY_MAP.get(cat_block.name, [])

    # Turn 2+: run with domain tools
    messages = [
        {"role": "user", "content": user_msg},
        {"role": "assistant", "content": r1.content},
        {"role": "user", "content": [{
            "type": "tool_result", "tool_use_id": cat_block.id,
            "content": f"Category selected: {cat_block.name}. Proceed with domain tools."
        }]}
    ]
    r2 = client.messages.create(
        model="claude-sonnet-4-6", max_tokens=1024, tools=domain_tools, messages=messages
    )
    # continue loop...
    return r2
